Here's the complete implementation of the serialization function using the Hexi library:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Serialize packet_id
        stream.serialise(packet_id);

        // Serialize username with length prefix
        stream.serialise(uint32_t(username.size()));
        if (!username.empty()) {
            stream.serialise(username.data(), username.size());
        }

        // Serialize scores with count prefix followed by elements
        stream.serialise(uint32_t(scores.size()));
        for (auto& score : scores) {
            stream.serialise(score);
        }

        // Serialize metadata as null-terminated string
        stream.serialise(metadata.c_str(), metadata.size() + 1); // +1 for null terminator
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a temporary non-const copy for serialization
    NetworkPacket temp_packet = packet;

    // Create output stream
    hexi::output_stream stream;

    // Serialize the packet
    temp_packet.serialise(stream);

    // Return the binary buffer
    return stream.buffer();
}
```

However, if you prefer a more optimized version that avoids creating a temporary copy, here's an alternative implementation:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Serialize packet_id
        stream << packet_id;

        // Serialize username with length prefix using write_container
        stream.write_container(username);

        // Serialize scores with count prefix using operator<< which internally calls write_container
        stream << scores;

        // Serialize metadata as null-terminated string using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    hexi::output_stream stream;

    // Manually serialize each field to avoid non-const method call
    stream << packet.packet_id;

    // Serialize username with length prefix
    stream.write_container(packet.username);

    // Serialize scores with count prefix
    stream << packet.scores;

    // Serialize metadata as null-terminated
    stream << hexi::null_terminated(packet.metadata);

    return stream.buffer();
}
```

Both implementations follow the requirements:
1. `packet_id` is serialized as uint32_t
2. `username` is serialized with length prefix
3. `scores` is serialized with count prefix followed by elements
4. `metadata` is serialized as null-terminated string

The second implementation is more idiomatic with the Hexi library and avoids the const-correctness issue by directly serializing the fields rather than calling the non-const `serialise` method on a const object.

