Here's the complete implementation using the Hexi library for zero-copy operations:

```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Use span() to read header with zero-copy
    auto header_span = buffer.subspan(0, sizeof(PacketHeader));

    // Create a zero-copy view of the header data
    auto header_view = std::span<const uint8_t, sizeof(PacketHeader)>(
        header_span.data(), sizeof(PacketHeader)
    );

    // Convert the span to PacketHeader using zero-copy reinterpretation
    const PacketHeader* header_ptr = reinterpret_cast<const PacketHeader*>(header_view.data());
    return *header_ptr;
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Use view() to read null-terminated string with zero-copy
    // Find the null terminator
    const uint8_t* null_pos = static_cast<const uint8_t*>(std::memchr(
        buffer.data(), 0, buffer.size()
    ));

    if (null_pos == nullptr) {
        // No null terminator found, return empty string_view
        return std::string_view();
    }

    // Calculate the length of the string (excluding null terminator)
    size_t length = null_pos - buffer.data();

    // Create a zero-copy string_view of the message
    return std::string_view(
        reinterpret_cast<const char*>(buffer.data()), 
        length
    );
}
```

