struct PacketHeader {
    uint8_t version;
    uint8_t flags;
    uint16_t packet_id;
};

PacketHeader read_packet_header(const std::span<const uint8_t> buffer) {
    // Use span() to read header with zero-copy
    if (buffer.size() < sizeof(PacketHeader)) {
        // Handle error - return default header or throw exception
        return PacketHeader{0, 0, 0};
    }

    // Create a fixed-size span for the header
    auto header_span = buffer.first<sizeof(PacketHeader)>();

    // Zero-copy conversion to PacketHeader
    return *reinterpret_cast<const PacketHeader*>(header_span.data());
}

std::string_view read_message_until_delimiter(const std::span<const uint8_t> buffer) {
    // Use view() to read null-terminated string with zero-copy
    auto it = std::find(buffer.begin(), buffer.end(), 0);

    if (it == buffer.end()) {
        // No null terminator found
        return std::string_view();
    }

    // Calculate length and create zero-copy string_view
    size_t length = std::distance(buffer.begin(), it);
    return std::string_view(
        reinterpret_cast<const char*>(buffer.data()), 
        length
    );
}
```

