```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <cstddef>

const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Return pointer to the beginning of the buffer for reading
    // If buffer is empty, return nullptr to avoid undefined behavior
    return buffer.empty() ? nullptr : buffer.data();
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Return pointer to the end of the buffer for writing
    // This allows appending new data after existing content
    return buffer.empty() ? buffer.data() : buffer.data() + buffer.size();
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    BufferInfo info;

    // Readable size is the current content size
    info.readable_size = buffer.size();

    // Free space depends on the vector's capacity
    // Capacity is the total allocated space, size is used space
    info.free_space = buffer.capacity() - buffer.size();

    return info;
}
```

**Alternative implementation if you need to track read position separately:**

If your buffer needs to track a separate read position (like a circular buffer), here's an alternative implementation:

