const uint8_t* get_read_pointer(const std::vector<uint8_t>& buffer) {
    // Get current read position from Hexi library
    size_t read_pos = hexi::get_read_position(buffer);

    // Ensure read position is within bounds
    if (read_pos >= buffer.size()) {
        return nullptr;
    }

    return buffer.data() + read_pos;
}

uint8_t* get_write_pointer(std::vector<uint8_t>& buffer) {
    // Get current write position from Hexi library
    size_t write_pos = hexi::get_write_position(buffer);

    // Ensure write position is within capacity
    if (write_pos >= buffer.capacity()) {
        return nullptr;
    }

    return buffer.data() + write_pos;
}

struct BufferInfo {
    size_t readable_size;
    size_t free_space;
};

BufferInfo check_buffer_space(const std::vector<uint8_t>& buffer) {
    BufferInfo info;

    // Get positions from Hexi
    size_t read_pos = hexi::get_read_position(buffer);
    size_t write_pos = hexi::get_write_position(buffer);

    // Calculate readable data (from read_pos to write_pos)
    if (write_pos >= read_pos) {
        info.readable_size = write_pos - read_pos;
    } else {
        // Handle wrap-around case for circular buffer
        info.readable_size = (buffer.capacity() - read_pos) + write_pos;
    }

    // Calculate free space
    info.free_space = buffer.capacity() - info.readable_size;

    return info;
}
