```cpp
#include <hexi/allocators/block_allocator.h>
#include <cstdint>
#include <iostream>
#include <vector>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    using namespace hexi;

    // Create a block allocator for integers with specified number of elements
    block_allocator<int, element_count> allocator;
    std::vector<int*> allocated_blocks;

    std::cout << "=== Block Allocator Free List Demonstration ===\n";
    std::cout << "Allocator capacity: " << element_count << " blocks\n\n";

    // Phase 1: Allocate all available blocks
    std::cout << "Phase 1: Allocating all " << element_count << " blocks...\n";
    for (size_t i = 0; i < element_count; ++i) {
        int* block = allocator.allocate(1);
        *block = static_cast<int>(i); // Store index in the block
        allocated_blocks.push_back(block);
        std::cout << "Allocated block " << i << " at address: " << block 
                  << " (value: " << *block << ")\n";
    }

    // Try to allocate one more (should fail)
    try {
        allocator.allocate(1);
        std::cout << "ERROR: Should have thrown exception!\n";
    } catch (const std::bad_alloc&) {
        std::cout << "Correctly threw bad_alloc when out of blocks\n\n";
    }

    // Phase 2: Deallocate blocks in LIFO order (simulating push() behavior)
    std::cout << "Phase 2: Deallocating blocks in LIFO order...\n";
    while (!allocated_blocks.empty()) {
        int* block = allocated_blocks.back();
        std::cout << "Deallocating block at: " << block 
                  << " (value: " << *block << ")\n";
        allocator.deallocate(block, 1);
        allocated_blocks.pop_back();
    }

    // Phase 3: Re-allocate blocks (demonstrating pop() behavior - LIFO order)
    std::cout << "\nPhase 3: Re-allocating blocks (should show LIFO order)...\n";
    for (size_t i = 0; i < element_count; ++i) {
        int* block = allocator.allocate(1);
        *block = static_cast<int>(i + 100); // Different values to distinguish
        std::cout << "Re-allocated block " << i << " at address: " << block 
                  << " (value: " << *block << ")\n";
        // Note: Addresses should be in reverse order of original deallocation
    }

    // Phase 4: Demonstrate mixed allocation/deallocation pattern
    std::cout << "\nPhase 4: Mixed allocation/deallocation pattern...\n";

    // Allocate 3 blocks
    int* block1 = allocator.allocate(1);
    int* block2 = allocator.allocate(1);
    int* block3 = allocator.allocate(1);

    *block1 = 201;
    *block2 = 202;
    *block3 = 203;

    std::cout << "Allocated 3 blocks:\n";
    std::cout << "Block 1: " << block1 << " (value: " << *block1 << ")\n";
    std::cout << "Block 2: " << block2 << " (value: " << *block2 << ")\n";
    std::cout << "Block 3: " << block3 << " (value: " << *block3 << ")\n";

    // Deallocate middle block first (block2)
    std::cout << "\nDeallocating middle block (block2) first...\n";
    allocator.deallocate(block2, 1);

    // Allocate again - should get block2 back (LIFO)
    int* block4 = allocator.allocate(1);
    *block4 = 204;
    std::cout << "Re-allocated block at: " << block4 
              << " (should be same as block2: " << (block4 == block2 ? "YES" : "NO") 
              << ")\n";

    // Clean up remaining blocks
    allocator.deallocate(block1, 1);
    allocator.deallocate(block3, 1);
    allocator.deallocate(block4, 1);

    std::cout << "\n=== Demonstration Complete ===\n";
    std::cout << "Summary:\n";
    std::cout << "- push() adds blocks to head of free list (LIFO behavior)\n";
    std::cout << "- pop() removes blocks from head of free list (LIFO behavior)\n";
    std::cout << "- Free list management is stack-based (last deallocated is first allocated)\n";
}

// Optional: Add a main function to test the demonstration
/*
int main() {
    demonstrate_block_allocator_behavior<5>(); // Test with 5 blocks
    return 0;
}
*/
```

This implementation demonstrates how the `block_allocator` internally manages its free list using `push()` and `pop()` operations, even though these methods are private. The demonstration shows:

1. **LIFO Behavior**: Blocks are allocated in reverse order of deallocation, showing the stack-like nature of the free list
2. **Free List Management**: How deallocated blocks are immediately available for reallocation
3. **Address Reuse**: The same memory addresses are reused, demonstrating the free list is working correctly
4. **Mixed Patterns**: Shows how the free list behaves with non-sequential allocation/deallocation patterns

The code includes comprehensive comments and output to clearly illustrate the internal free list management behavior.

