Here's the complete implementation of the functions using the Hexi library's `intrusive_storage`:

```cpp
#include <hexi/detail/intrusive_storage.h>
#include <vector>
#include <cstdint>
#include <algorithm>

template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Get the current readable size
    size_t readable_size = storage.readable();

    // Determine how many bytes we can actually preview
    size_t bytes_to_copy = std::min(bytes_to_preview, readable_size);

    // Create result vector
    std::vector<uint8_t> result;
    result.reserve(bytes_to_copy);

    // Preview data without consuming (using peek functionality)
    // Since intrusive_storage doesn't have a direct peek method, we need to read and then restore the state
    auto& mutable_storage = const_cast<hexi::detail::intrusive_storage<block_size>&>(storage);

    // Save the current read position
    size_t original_read_pos = mutable_storage.tell_read();

    // Read the data into our result vector
    for (size_t i = 0; i < bytes_to_copy; ++i) {
        uint8_t byte;
        if (mutable_storage.read(&byte, 1)) {
            result.push_back(byte);
        } else {
            break; // Should not happen since we checked readable size
        }
    }

    // Restore the original read position
    mutable_storage.seek_read(original_read_pos);

    return result;
}

