#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    if (src == nullptr || dst == nullptr) {
        return false;
    }

    const char* src_start = static_cast<const char*>(src);
    const char* src_end = src_start + src_len;
    const char* dst_start = static_cast<const char*>(dst);
    const char* dst_end = dst_start + dst_len;

    // Check if regions overlap by comparing their boundaries
    return (src_start < dst_end && dst_start < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    if (destination == nullptr || source == nullptr || length == 0) {
        return false;
    }

    // Check for overlap using the check_regions_overlap function
    if (check_regions_overlap(source, length, destination, length)) {
        return false; // Overlap detected, copy is unsafe
    }

    // Perform the memory copy since regions don't overlap
    std::memcpy(destination, source, length);
    return true;
}
```

This implementation:

1. **`check_regions_overlap`**: 
   - Converts the void pointers to char pointers for byte-wise arithmetic
   - Calculates the end boundaries of both memory regions
   - Uses boundary comparison to detect overlap (if one region starts before the other ends)
   - Returns `true` if regions overlap, `false` otherwise

2. **`safe_memory_copy`**:
   - First performs null checks and handles zero-length case
   - Uses `check_regions_overlap` to verify the source and destination regions don't overlap
   - Returns `false` if overlap is detected (unsafe to copy)
   - Uses `std::memcpy` to perform the actual copy if regions are safe
   - Returns `true` on successful copy

The overlap detection logic correctly handles all cases including:
- Completely separate regions
- Adjacent regions (no overlap)
- Partial overlaps
- Complete overlaps (one region entirely within another)

