#include <hexi/exception.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct UnderrunInfo {
    std::size_t read_size;
    std::size_t total_read;
    std::size_t buff_size;
    bool occurred;
};

UnderrunInfo catch_buffer_underrun() {
    UnderrunInfo info = {0, 0, 0, false};

    try {
        // Re-throw any currently caught exception to handle it
        throw;
    } catch (const hexi::buffer_underrun& e) {
        // Extract information from the buffer_underrun exception
        info.read_size = e.get_read_size();
        info.total_read = e.get_total_read();
        info.buff_size = e.get_buffer_size();
        info.occurred = true;
    } catch (...) {
        // Catch any other exceptions and leave occurred as false
        info.occurred = false;
    }

    return info;
}

UnderrunInfo safe_read_with_underrun_check(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, void* destination, std::size_t length) {
    UnderrunInfo info = {0, 0, 0, false};

    try {
        // Attempt to read from the buffer
        buffer.read(destination, length);
        info.occurred = false;
    } catch (const hexi::buffer_underrun& e) {
        // Extract information from the caught buffer_underrun exception
        info.read_size = e.get_read_size();
        info.total_read = e.get_total_read();
        info.buff_size = e.get_buffer_size();
        info.occurred = true;
    } catch (...) {
        // Handle any other exceptions that might occur
        info.occurred = false;
        // You might want to re-throw or handle other exceptions differently
    }

    return info;
}
```

