TEST(StreamReadLimit, CatchException) {
    auto info = catch_stream_read_limit();

    EXPECT_TRUE(info.occurred);
    EXPECT_GT(info.read_size, 0);
    EXPECT_EQ(10, info.read_limit);
}

TEST(StreamReadLimit, SafeReadWithinLimit) {
    std::vector<std::byte> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer, hexi::init_empty);
    hexi::pmc::binary_stream stream(adaptor, 100);

    uint32_t value = 12345;
    stream << value;

    uint32_t read_value = 0;
    // safe_read_with_limit_check expects byte count, so pass sizeof(read_value)
    auto info = safe_read_with_limit_check(stream, &read_value, sizeof(read_value));

    EXPECT_FALSE(info.occurred);
    EXPECT_EQ(value, read_value);
}

TEST(StreamReadLimit, ExtractExceptionInfo) {
    std::vector<std::byte> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer, hexi::init_empty);

    // Create stream with small read limit (5 bytes)
    hexi::pmc::binary_stream stream(adaptor, 5);

    // Write enough data (100 bytes) so buffer has enough data
    // but read limit is only 5 bytes
    std::vector<std::byte> data(100, std::byte{0xAA});
    adaptor.write(data.data(), data.size());

    // First read 3 bytes (within limit)
    std::vector<std::byte> dest1(3);
    auto info1 = safe_read_with_limit_check(stream, dest1.data(), dest1.size());
    EXPECT_FALSE(info1.occurred);

    // Then try to read more than the remaining read limit
    // Remaining limit is 5 - 3 = 2 bytes, so reading 10 bytes should trigger stream_read_limit
    std::vector<std::byte> dest2(10);
    auto info2 = safe_read_with_limit_check(stream, dest2.data(), dest2.size());

    EXPECT_TRUE(info2.occurred);
    EXPECT_EQ(5, info2.read_limit);
    EXPECT_GT(info2.total_read, 0);
}

