```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct CompactPacket {
    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    hexi::serializer s;

    // Serialize packet_id as varint
    s << hexi::varint(packet.packet_id);

    // Serialize tags vector using prefixed_varint for size
    s << hexi::prefixed_varint(packet.tags.size());
    for (const auto& tag : packet.tags) {
        // Serialize each tag string using prefixed_varint
        s << hexi::prefixed_varint(tag);
    }

    // Serialize data string using prefixed_varint
    s << hexi::prefixed_varint(packet.data);

    // Convert serializer buffer to vector<uint8_t>
    auto buffer = s.buffer();
    return std::vector<uint8_t>(buffer.begin(), buffer.end());
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    hexi::deserializer d(buffer.data(), buffer.size());
    CompactPacket packet;

    // Deserialize packet_id as varint
    d >> hexi::varint(packet.packet_id);

    // Deserialize tags vector size using prefixed_varint
    uint64_t tags_size;
    d >> hexi::prefixed_varint(tags_size);

    // Deserialize each tag string
    packet.tags.resize(tags_size);
    for (size_t i = 0; i < tags_size; ++i) {
        d >> hexi::prefixed_varint(packet.tags[i]);
    }

    // Deserialize data string using prefixed_varint
    d >> hexi::prefixed_varint(packet.data);

    return packet;
}
