struct Header {
    uint32_t magic;
    uint16_t version;
};

Header peek_header_without_reading(const std::vector<uint8_t>& buffer) {
    // Create buffer read adaptor
    hexi::pmc::buffer_read_adaptor adaptor(buffer.data(), buffer.size());

    // Use copy() to peek at header without advancing read cursor
    Header header;
    adaptor.copy(reinterpret_cast<uint8_t*>(&header), sizeof(Header));

    // Use read_ptr() to verify pointer position hasn't changed
    const uint8_t* ptr = adaptor.read_ptr(sizeof(Header));
    if (ptr == nullptr) {
        throw std::runtime_error("Not enough data in buffer");
    }

    // Verify the data matches what we copied
    if (std::memcmp(&header, ptr, sizeof(Header)) != 0) {
        throw std::runtime_error("Data verification failed");
    }

    return header;
}

std::vector<uint8_t> peek_then_conditionally_read(const std::vector<uint8_t>& buffer) {
    // Create buffer read adaptor
    hexi::pmc::buffer_read_adaptor adaptor(buffer.data(), buffer.size());

    // Use copy() to peek at first byte
    uint8_t first_byte;
    if (adaptor.remaining() < 1) {
        return {}; // Return empty vector if not enough data
    }

    adaptor.copy(&first_byte, 1);

    // Condition: if first byte is non-zero, read more data
    std::vector<uint8_t> result;
    if (first_byte != 0) {
        // Determine how much data to read based on the peeked value
        size_t data_size = std::min(static_cast<size_t>(first_byte), adaptor.remaining());

        if (data_size > 0) {
            result.resize(data_size);
            // Use read() to consume the data
            adaptor.read(result.data(), data_size);
        }
    }

    return result;
}
