Here's the complete implementation of the file with all the required functions:

```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <span>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor.write(sensor_id);

        // Write temperatures count first
        uint32_t count = static_cast<uint32_t>(temperatures.size());
        adaptor.write(count);

        // Convert and write each temperature value
        for (const float& temp : temperatures) {
            float little_endian_temp = hexi::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(little_endian_temp);
        }

        // Convert and write pressure
        double little_endian_pressure = hexi::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(little_endian_pressure);
    }

    void serialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor.read(sensor_id);

        // Read temperatures count
        uint32_t count;
        adaptor.read(count);

        // Resize vector and read temperatures
        temperatures.resize(count);
        for (float& temp : temperatures) {
            adaptor.read(temp);
            hexi::little_to_native_inplace(temp);
        }

        // Read and convert pressure
        adaptor.read(pressure);
        hexi::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    hexi::stream stream;
    data.serialise(stream);
    return stream.data();
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    hexi::stream stream(buffer);
    MeasurementData data;
    data.serialise(stream);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::stream stream(buffer);
    SensorInfo info;

    // Extract null-terminated sensor name if present
    info.sensor_name = stream.view('\0');

    // Check bounds before reading sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.read(info.sensor_id);

    // Skip remaining data
    stream.skip(stream.remaining());

    return info;
}
